import{_ as o,o as t,c as l,ag as e}from"./chunks/framework.Cqf6AMW8.js";const f=JSON.parse('{"title":"C 语言 IO 与流程控制","description":"C 语言输入输出函数与流程控制语句相关知识。","frontmatter":{"title":"C 语言 IO 与流程控制","description":"C 语言输入输出函数与流程控制语句相关知识。","date":"2026-04-21T00:00:00.000Z","tags":["C语言","IO","流程控制"],"sidebar":"auto"},"headers":[],"relativePath":"docs/backend/C/c-2-IO与流程控制.md","filePath":"docs/backend/C/c-2-IO与流程控制.md","lastUpdated":1776715536000}'),n={name:"docs/backend/C/c-2-IO与流程控制.md"};function c(r,i,d,a,s,u){return t(),l("div",null,[...i[0]||(i[0]=[e('<h1 id="后端" tabindex="-1">后端 <a class="header-anchor" href="#后端" aria-label="Permalink to &quot;后端&quot;">​</a></h1><h1 id="c语言io与流程控制" tabindex="-1">C语言IO与流程控制 <a class="header-anchor" href="#c语言io与流程控制" aria-label="Permalink to &quot;C语言IO与流程控制&quot;">​</a></h1><h2 id="_1-输入输出函数" tabindex="-1">1. 输入输出函数 <a class="header-anchor" href="#_1-输入输出函数" aria-label="Permalink to &quot;1. 输入输出函数&quot;">​</a></h2><ul><li><p><strong>printf()</strong>：输出格式化数据到标准输出</p><ul><li>语法格式：<code>int printf(const char *format, ...);</code></li><li>示例：<code>printf(&quot;Hello, %s!\\n&quot;, name);</code></li></ul></li><li><p><strong>scanf()</strong>：从标准输入读取格式化数据</p><ul><li>语法格式：<code>int scanf(const char *format, ...);</code></li><li>示例：<code>scanf(&quot;%d&quot;, &amp;num);</code></li></ul></li><li><p><strong>getchar()</strong>：从标准输入读取单个字符</p><ul><li>语法格式：<code>int getchar(void);</code></li><li>示例：<code>char c = getchar();</code></li></ul></li><li><p><strong>putchar()</strong>：输出单个字符到标准输出</p><ul><li>语法格式：<code>int putchar(int c);</code></li><li>示例：<code>putchar(&#39;A&#39;);</code></li></ul></li><li><p><strong>fgets()</strong>：从流中读取字符串</p><ul><li>语法格式：<code>char *fgets(char *s, int size, FILE *stream);</code></li><li>示例：<code>fgets(buffer, 100, stdin);</code></li></ul></li><li><p><strong>fputs()</strong>：向流中写入字符串</p><ul><li>语法格式：<code>int fputs(const char *s, FILE *stream);</code></li><li>示例：<code>fputs(&quot;Hello&quot;, stdout);</code></li></ul></li></ul><p>======================================================</p><h2 id="_2-流程控制语句" tabindex="-1">2. 流程控制语句 <a class="header-anchor" href="#_2-流程控制语句" aria-label="Permalink to &quot;2. 流程控制语句&quot;">​</a></h2><ul><li><p><strong>if</strong>：条件判断</p><ul><li>语法格式：<code>if (条件) { 语句块 }</code></li><li>示例：<code>if (x &gt; 0) { printf(&quot;Positive\\n&quot;); }</code></li></ul></li><li><p><strong>if-else</strong>：条件判断与分支</p><ul><li>语法格式：<code>if (条件) { 语句块1 } else { 语句块2 }</code></li><li>示例：<code>if (x &gt; 0) { printf(&quot;Positive\\n&quot;); } else { printf(&quot;Non-positive\\n&quot;); }</code></li></ul></li><li><p><strong>if-else if-else</strong>：多条件判断</p><ul><li>语法格式：<code>if (条件1) { 语句块1 } else if (条件2) { 语句块2 } else { 语句块3 }</code></li><li>示例：<code>if (x &gt; 0) { printf(&quot;Positive\\n&quot;); } else if (x &lt; 0) { printf(&quot;Negative\\n&quot;); } else { printf(&quot;Zero\\n&quot;); }</code></li></ul></li><li><p><strong>switch</strong>：多分支选择</p><ul><li>语法格式：<code>switch (表达式) { case 值1: 语句块1; break; case 值2: 语句块2; break; ... default: 语句块n; }</code></li><li>示例：<code>switch (grade) { case &#39;A&#39;: printf(&quot;Excellent\\n&quot;); break; case &#39;B&#39;: printf(&quot;Good\\n&quot;); break; default: printf(&quot;Pass\\n&quot;); }</code></li></ul></li><li><p><strong>while</strong>：当条件为真时循环</p><ul><li>语法格式：<code>while (条件) { 循环体 }</code></li><li>示例：<code>while (i &lt; 10) { printf(&quot;%d\\n&quot;, i); i++; }</code></li></ul></li><li><p><strong>do-while</strong>：先执行一次循环体，再判断条件</p><ul><li>语法格式：<code>do { 循环体 } while (条件);</code></li><li>示例：<code>do { printf(&quot;%d\\n&quot;, i); i++; } while (i &lt; 10);</code></li></ul></li><li><p><strong>for</strong>：初始化、条件、更新的循环</p><ul><li>语法格式：<code>for (初始化; 条件; 更新) { 循环体 }</code></li><li>示例：<code>for (int i = 0; i &lt; 10; i++) { printf(&quot;%d\\n&quot;, i); }</code></li></ul></li><li><p><strong>break</strong>：跳出当前循环或switch</p><ul><li>语法格式：<code>break;</code></li><li>示例：<code>for (int i = 0; i &lt; 10; i++) { if (i == 5) break; printf(&quot;%d\\n&quot;, i); }</code></li></ul></li><li><p><strong>continue</strong>：跳过本次循环，进入下一次循环</p><ul><li>语法格式：<code>continue;</code></li><li>示例：<code>for (int i = 0; i &lt; 10; i++) { if (i % 2 == 0) continue; printf(&quot;%d\\n&quot;, i); }</code></li></ul></li><li><p><strong>return</strong>：从函数返回值</p><ul><li>语法格式：<code>return 表达式;</code></li><li>示例：<code>int add(int a, int b) { return a + b; }</code></li></ul></li><li><p><strong>goto</strong>：无条件跳转到指定标签</p><ul><li>语法格式：<code>goto 标签;</code></li><li>示例：<code>goto end; ... end: printf(&quot;End\\n&quot;);</code></li></ul></li></ul>',7)])])}const g=o(n,[["render",c]]);export{f as __pageData,g as default};
